// Fallback chain: requested lang -> en -> it
export function t(lang, key) {
  const l = lang || 'en';
  if (T[l] && T[l][key] !== undefined) return T[l][key];
  if (T.en && T.en[key] !== undefined) return T.en[key];
  if (T.it && T.it[key] !== undefined) return T.it[key];
  return key;
}

// For languages not in T, map to closest
export function mapLang(code) {
  if (T[code]) return code;
  // Map regional variants
  const map = { 'id':'en', 'ms':'en', 'nl':'en', 'pl':'en', 'sv':'en', 'el':'en', 'cs':'en', 'ro':'en', 'hu':'en', 'fi':'en' };
  return map[code] || 'en';
}

export default T;
